class CombinationIterator {
public:
    vector<string> combinations;
    int index = 0;

    CombinationIterator(string characters, int combinationLength) {
        generateCombinations(characters, combinationLength, 0, "");
    }

    string next() {
        return combinations[index++];
    }

    bool hasNext() {
        return index < combinations.size();
    }

    void generateCombinations(string characters, int combinationLength, int start, string current) {
        if (current.size() == combinationLength) {
            combinations.push_back(current);
            return;
        }
        for (int i = start; i < characters.size(); i++) {
            generateCombinations(characters, combinationLength, i + 1, current + characters[i]);
        }
    }
};
```
